mapper.select:
SELECT s.seller_id AS seller_code, s.brand_name_ko AS seller_name, CAST(0 AS DOUBLE) AS estimated_cost, CAST(0 AS DOUBLE) AS mom_growth, CAST(0 AS DOUBLE) AS turnover_rate FROM seller s
s.tenant_id = #{tenantId}
AND s.seller_id = #{sellerId}
AND ( s.seller_id LIKE CONCAT('%', #{keyword}, '%') OR s.brand_name_ko LIKE CONCAT('%', #{keyword}, '%') OR s.brand_name_en LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY s.created_at DESC, s.seller_id ASC

SELECT s.seller_id AS seller_code, s.brand_name_ko AS seller_name, CAST(0 AS DOUBLE) AS month_revenue, 0 AS total_orders, CAST(0 AS DOUBLE) AS avg_order_value FROM seller s
s.tenant_id = #{tenantId}
AND s.seller_id = #{sellerId}
AND ( s.seller_id LIKE CONCAT('%', #{keyword}, '%') OR s.brand_name_ko LIKE CONCAT('%', #{keyword}, '%') OR s.brand_name_en LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY s.created_at DESC, s.seller_id ASC

SELECT SUM(CASE WHEN s.status = 'ACTIVE' THEN 1 ELSE 0 END) AS active_seller_count, SUM(CASE WHEN s.status = 'INACTIVE' THEN 1 ELSE 0 END) AS inactive_seller_count, COUNT(*) AS total_seller_count FROM seller s
s.tenant_id = #{tenantId}
AND s.status = #{status}
